import { describe, it, expect, beforeEach } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
import { PreferencesService, resetPreferencesIdCounter } from '../../src/services/preferences.service.js';
import { NotificationHistoryService, resetNotificationLogIdCounter } from '../../src/services/notification-history.service.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailNotificationAdapter, InMemoryEmailTransport } from '../../src/adapters/email.adapter.js';
import { SmsNotificationAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
import { WebhookNotificationAdapter, InMemoryWebhookTransport } from '../../src/adapters/webhook.adapter.js';
import { Database } from '../../src/utils/database.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent } from '../../src/events/event-types.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

/**
 * Integration tests for the full notification pipeline:
 * EventBus → NotificationService → PreferencesService → Adapters → History
 */
describe('Notification Pipeline Integration', () => {
  let db: Database;
  let eventBus: EventBus;
  let preferencesRepo: PreferencesRepository;
  let preferencesService: PreferencesService;
  let notificationLogRepo: NotificationLogRepository;
  let historyService: NotificationHistoryService;
  let notificationService: NotificationService;

  let emailTransport: InMemoryEmailTransport;
  let smsTransport: InMemorySmsTransport;
  let webhookTransport: InMemoryWebhookTransport;

  const testUser: User = {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2026-01-01'),
    updatedAt: new Date('2026-01-01'),
  };

  const testOrder: Order = {
    id: 'order-1',
    userId: 'user-1',
    items: [
      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
    ],
    total: 45,
    status: 'pending',
    createdAt: new Date('2026-01-15'),
    updatedAt: new Date('2026-01-15'),
  };

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    resetNotificationIdCounter();
    resetPreferencesIdCounter();
    resetNotificationLogIdCounter();

    // Set up repositories
    preferencesRepo = new PreferencesRepository(db);
    preferencesService = new PreferencesService(preferencesRepo);
    notificationLogRepo = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(notificationLogRepo);

    // Set up in-memory transports
    emailTransport = new InMemoryEmailTransport();
    smsTransport = new InMemorySmsTransport();
    webhookTransport = new InMemoryWebhookTransport();

    // Create notification service with preferences and history
    notificationService = new NotificationService(eventBus, {
      preferencesService,
      historyService,
    });

    // Register adapters with in-memory transports
    notificationService.registerAdapter(
      new EmailNotificationAdapter({ transport: emailTransport }),
    );
    notificationService.registerAdapter(
      new SmsNotificationAdapter({ transport: smsTransport }),
    );
    notificationService.registerAdapter(
      new WebhookNotificationAdapter({ transport: webhookTransport }),
    );
  });

  describe('email channel — end-to-end', () => {
    it('should deliver email notification when email preferences are enabled', async () => {
      // Default preferences have email enabled
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Email was sent through the transport
      const inbox = emailTransport.getInbox();
      expect(inbox).toHaveLength(1);
      expect(inbox[0]!.to).toBe('alice@example.com');
      expect(inbox[0]!.subject).toContain('Order Confirmation');

      // Notification recorded in service
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.success).toBe(true);
      expect(notifications[0]!.channel).toBe('email');

      // History logged
      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('delivered');
      expect(logs[0]!.channel).toBe('email');
      expect(logs[0]!.type).toBe('order-confirmation');
    });

    it('should deliver welcome email on user:created event', async () => {
      const event: UserCreatedEvent = {
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const inbox = emailTransport.getInbox();
      expect(inbox).toHaveLength(1);
      expect(inbox[0]!.subject).toContain('Welcome');

      const logs = historyService.getByRecipient('alice@example.com');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.type).toBe('welcome');
      expect(logs[0]!.status).toBe('delivered');
    });

    it('should deliver order status update email on order:status-changed event', async () => {
      const event: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: { ...testOrder, status: 'shipped' },
        previousStatus: 'confirmed',
        newStatus: 'shipped',
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // order:status-changed uses order.userId as recipient, which is not an email.
      // The email adapter's default resolver requires '@' — so it will fail to resolve.
      // This is expected: userId-based recipients need a custom RecipientResolver.
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);

      const logs = historyService.query({ type: 'order-status-update' });
      expect(logs).toHaveLength(1);
    });
  });

  describe('SMS channel — end-to-end', () => {
    it('should deliver SMS notification when SMS preferences are enabled', async () => {
      const result = await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+1-555-123-4567',
        subject: 'Order Placed',
        body: 'Your order has been placed.',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(true);
      expect(result.channel).toBe('sms');

      // SMS delivered through transport
      const messages = smsTransport.getMessages();
      expect(messages).toHaveLength(1);
      expect(messages[0]!.to).toBe('+1-555-123-4567');
      expect(messages[0]!.body).toContain('Order Placed');

      // History recorded
      const logs = historyService.getByRecipient('+1-555-123-4567');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('delivered');
      expect(logs[0]!.channel).toBe('sms');
    });

    it('should truncate long SMS messages', async () => {
      const longBody = 'A'.repeat(200);
      await notificationService.send({
        type: 'welcome',
        channel: 'sms',
        recipient: '+1-555-000-0000',
        subject: 'Welcome',
        body: longBody,
        priority: 'low',
        metadata: { userId: 'user-1' },
      });

      const messages = smsTransport.getMessages();
      expect(messages).toHaveLength(1);
      // Default max length is 160
      expect(messages[0]!.body.length).toBeLessThanOrEqual(160);
      expect(messages[0]!.body).toMatch(/\.\.\.$/);
    });
  });

  describe('webhook channel — end-to-end', () => {
    it('should deliver webhook notification with URL recipient', async () => {
      const result = await notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/orders',
        subject: 'Order Placed',
        body: 'Order order-1 placed.',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(true);
      expect(result.channel).toBe('webhook');

      // Webhook delivered through transport
      const deliveries = webhookTransport.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]!.url).toBe('https://hooks.example.com/orders');
      expect(deliveries[0]!.method).toBe('POST');

      const payload = JSON.parse(deliveries[0]!.body);
      expect(payload.type).toBe('order-confirmation');
      expect(payload.subject).toBe('Order Placed');

      // History recorded
      const logs = historyService.getByRecipient('https://hooks.example.com/orders');
      expect(logs).toHaveLength(1);
      expect(logs[0]!.status).toBe('delivered');
      expect(logs[0]!.channel).toBe('webhook');
    });
  });

  describe('history logging', () => {
    it('should log all notification outcomes in history', async () => {
      // Send a successful email
      await notificationService.send({
        type: 'welcome',
        channel: 'email',
        recipient: 'bob@example.com',
        subject: 'Welcome',
        body: 'Hello!',
        priority: 'low',
        metadata: { userId: 'user-2' },
      });

      // Send a successful webhook
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/test',
        subject: 'Order',
        body: 'Placed',
        priority: 'normal',
        metadata: { userId: 'user-3' },
      });

      // Send to a channel with no adapter (in-app)
      await notificationService.send({
        type: 'welcome',
        channel: 'in-app',
        recipient: 'user-4',
        subject: 'Welcome',
        body: 'Hi',
        priority: 'low',
      });

      expect(historyService.count()).toBe(3);

      const delivered = historyService.query({ status: 'delivered' });
      expect(delivered).toHaveLength(2);

      const failed = historyService.query({ status: 'failed' });
      expect(failed).toHaveLength(1);
      expect(failed[0]!.channel).toBe('in-app');
    });

    it('should log suppressed notifications in history', async () => {
      // Disable email for user-1
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      await notificationService.send({
        type: 'welcome',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Welcome',
        body: 'Hello!',
        priority: 'low',
        metadata: { userId: 'user-1' },
      });

      const logs = historyService.query({ status: 'suppressed' });
      expect(logs).toHaveLength(1);
      expect(logs[0]!.recipient).toBe('alice@example.com');
      expect(logs[0]!.error).toBe('Suppressed by user preferences');
    });

    it('should support querying history by channel and type', async () => {
      await notificationService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'a@example.com',
        subject: 'Order',
        body: 'Placed',
        priority: 'normal',
        metadata: { userId: 'user-10' },
      });

      await notificationService.send({
        type: 'welcome',
        channel: 'sms',
        recipient: '+1-555-000-0001',
        subject: 'Welcome',
        body: 'Hi',
        priority: 'low',
        metadata: { userId: 'user-11' },
      });

      await notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/x',
        subject: 'Order',
        body: 'Placed',
        priority: 'normal',
        metadata: { userId: 'user-12' },
      });

      expect(historyService.query({ channel: 'email' })).toHaveLength(1);
      expect(historyService.query({ channel: 'sms' })).toHaveLength(1);
      expect(historyService.query({ channel: 'webhook' })).toHaveLength(1);
      expect(historyService.query({ type: 'order-confirmation' })).toHaveLength(2);
      expect(historyService.query({ type: 'welcome' })).toHaveLength(1);
    });
  });

  describe('user preferences enforcement', () => {
    it('should suppress email when email channel is globally disabled', async () => {
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // No email sent
      expect(emailTransport.getInbox()).toHaveLength(0);

      // Notification recorded as failed (suppressed)
      const notifications = notificationService.getNotifications();
      expect(notifications).toHaveLength(1);
      expect(notifications[0]!.success).toBe(false);
      expect(notifications[0]!.error).toBe('Suppressed by user preferences');

      // History shows suppressed
      const logs = historyService.query({ status: 'suppressed' });
      expect(logs).toHaveLength(1);
    });

    it('should suppress SMS when SMS channel is globally disabled', async () => {
      preferencesService.updateSmsPreferences('user-1', { enabled: false });

      const result = await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+1-555-123-4567',
        subject: 'Order',
        body: 'Placed',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(smsTransport.getMessages()).toHaveLength(0);
    });

    it('should suppress webhook when webhook channel is globally disabled', async () => {
      preferencesService.updateWebhookPreferences('user-1', { enabled: false });

      const result = await notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/test',
        subject: 'Order',
        body: 'Placed',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      expect(result.success).toBe(false);
      expect(result.error).toBe('Suppressed by user preferences');
      expect(webhookTransport.getDeliveries()).toHaveLength(0);
    });

    it('should suppress notification when specific category is disabled', async () => {
      preferencesService.updateEmailPreferences('user-1', {
        categories: { orderConfirmations: false, orderStatusUpdates: true, welcomeMessages: true, accountUpdates: true },
      });

      // order-confirmation maps to orderConfirmations category
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(emailTransport.getInbox()).toHaveLength(0);

      const logs = historyService.query({ status: 'suppressed' });
      expect(logs).toHaveLength(1);
    });

    it('should allow notification when category is enabled but other categories are disabled', async () => {
      preferencesService.updateEmailPreferences('user-1', {
        categories: { orderConfirmations: true, orderStatusUpdates: false, welcomeMessages: false, accountUpdates: false },
      });

      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // order-confirmation should still go through since orderConfirmations is enabled
      expect(emailTransport.getInbox()).toHaveLength(1);

      const logs = historyService.query({ status: 'delivered' });
      expect(logs).toHaveLength(1);
    });

    it('should enforce per-channel preferences independently', async () => {
      // Disable email, keep SMS enabled
      preferencesService.updateEmailPreferences('user-1', { enabled: false });

      const emailResult = await notificationService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Order',
        body: 'Placed',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      const smsResult = await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+1-555-123-4567',
        subject: 'Order',
        body: 'Placed',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      expect(emailResult.success).toBe(false);
      expect(emailResult.error).toBe('Suppressed by user preferences');
      expect(smsResult.success).toBe(true);

      expect(emailTransport.getInbox()).toHaveLength(0);
      expect(smsTransport.getMessages()).toHaveLength(1);
    });
  });

  describe('notification ordering', () => {
    it('should preserve send order for same recipient across the full pipeline', async () => {
      const deliveryOrder: string[] = [];
      const originalEmailSendMail = emailTransport.sendMail.bind(emailTransport);

      // Wrap the transport to track delivery order
      emailTransport.sendMail = async (email) => {
        deliveryOrder.push(email.subject);
        return originalEmailSendMail(email);
      };

      // Re-register the adapter with the patched transport
      notificationService.registerAdapter(
        new EmailNotificationAdapter({ transport: emailTransport }),
      );

      // Send multiple notifications to the same user concurrently
      const promises = [
        notificationService.send({
          type: 'order-confirmation',
          channel: 'email',
          recipient: 'alice@example.com',
          subject: 'Notification 1',
          body: 'First',
          priority: 'normal',
          metadata: { userId: 'user-1' },
        }),
        notificationService.send({
          type: 'order-status-update',
          channel: 'email',
          recipient: 'alice@example.com',
          subject: 'Notification 2',
          body: 'Second',
          priority: 'normal',
          metadata: { userId: 'user-1' },
        }),
        notificationService.send({
          type: 'welcome',
          channel: 'email',
          recipient: 'alice@example.com',
          subject: 'Notification 3',
          body: 'Third',
          priority: 'low',
          metadata: { userId: 'user-1' },
        }),
      ];

      await Promise.all(promises);

      // All three delivered in send order
      expect(deliveryOrder).toEqual([
        'Notification 1',
        'Notification 2',
        'Notification 3',
      ]);

      // History should also reflect the order
      const logs = historyService.query({ channel: 'email' });
      expect(logs).toHaveLength(3);
      expect(logs.map((l) => l.subject)).toEqual([
        'Notification 1',
        'Notification 2',
        'Notification 3',
      ]);
    });
  });

  describe('multi-channel delivery', () => {
    it('should deliver the same notification type through multiple channels', async () => {
      // Send order confirmation via all three channels
      const emailResult = await notificationService.send({
        type: 'order-confirmation',
        channel: 'email',
        recipient: 'alice@example.com',
        subject: 'Order Placed',
        body: 'Your order is placed.',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      const smsResult = await notificationService.send({
        type: 'order-confirmation',
        channel: 'sms',
        recipient: '+1-555-123-4567',
        subject: 'Order Placed',
        body: 'Your order is placed.',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      const webhookResult = await notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/orders',
        subject: 'Order Placed',
        body: 'Your order is placed.',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      });

      expect(emailResult.success).toBe(true);
      expect(smsResult.success).toBe(true);
      expect(webhookResult.success).toBe(true);

      // All three channels received their delivery
      expect(emailTransport.getInbox()).toHaveLength(1);
      expect(smsTransport.getMessages()).toHaveLength(1);
      expect(webhookTransport.getDeliveries()).toHaveLength(1);

      // History shows all three
      expect(historyService.count()).toBe(3);
      const logs = historyService.query({ type: 'order-confirmation' });
      expect(logs).toHaveLength(3);
      const channels = logs.map((l) => l.channel).sort();
      expect(channels).toEqual(['email', 'sms', 'webhook']);
    });
  });

  describe('event-driven pipeline', () => {
    it('should handle multiple events in sequence with history tracking', async () => {
      // 1. User created → welcome email
      await eventBus.emit({
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      // 2. Order created → confirmation email
      await eventBus.emit({
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      // 3. Order status changed → status update email
      await eventBus.emit({
        type: 'order:status-changed',
        order: { ...testOrder, status: 'confirmed' },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      } satisfies OrderStatusChangedEvent);

      // Three notifications sent through the pipeline
      expect(notificationService.getNotificationCount()).toBe(3);
      expect(historyService.count()).toBe(3);

      // History types match
      const logs = historyService.query({});
      const types = logs.map((l) => l.type);
      expect(types).toContain('welcome');
      expect(types).toContain('order-confirmation');
      expect(types).toContain('order-status-update');
    });

    it('should respect preferences when events trigger notifications', async () => {
      // Disable welcome messages for user-1
      preferencesService.updateEmailPreferences('user-1', {
        categories: { orderConfirmations: true, orderStatusUpdates: true, welcomeMessages: false, accountUpdates: true },
      });

      // Welcome should be suppressed
      await eventBus.emit({
        type: 'user:created',
        user: testUser,
        timestamp: new Date(),
      } satisfies UserCreatedEvent);

      // Order confirmation should go through
      await eventBus.emit({
        type: 'order:created',
        order: testOrder,
        user: testUser,
        timestamp: new Date(),
      } satisfies OrderCreatedEvent);

      expect(notificationService.getNotificationCount()).toBe(2);

      const suppressed = historyService.query({ status: 'suppressed' });
      expect(suppressed).toHaveLength(1);
      expect(suppressed[0]!.type).toBe('welcome');

      const delivered = historyService.query({ status: 'delivered' });
      expect(delivered).toHaveLength(1);
      expect(delivered[0]!.type).toBe('order-confirmation');
    });
  });
});

