describe('notification ordering', () => {
  it('should preserve send order for same recipient across the full pipeline', async () => {
    const deliveryOrder: string[] = [];

    // Use webhook channel to avoid email template rendering rewriting subjects
    const trackingTransport: InMemoryWebhookTransport & { deliveryOrder: string[] } = Object.assign(
      new InMemoryWebhookTransport(),
      { deliveryOrder },
    );
    const originalPost = trackingTransport.post.bind(trackingTransport);
    trackingTransport.post = async (payload) => {
      const parsed = JSON.parse(payload.body);
      deliveryOrder.push(parsed.subject);
      return originalPost(payload);
    };

    notificationService.registerAdapter(
      new WebhookNotificationAdapter({ transport: trackingTransport }),
    );

    // Send multiple notifications to the same user concurrently
    const promises = [
      notificationService.send({
        type: 'order-confirmation',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/test',
        subject: 'Notification 1',
        body: 'First',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      }),
      notificationService.send({
        type: 'order-status-update',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/test',
        subject: 'Notification 2',
        body: 'Second',
        priority: 'normal',
        metadata: { userId: 'user-1' },
      }),
      notificationService.send({
        type: 'welcome',
        channel: 'webhook',
        recipient: 'https://hooks.example.com/test',
        subject: 'Notification 3',
        body: 'Third',
        priority: 'low',
        metadata: { userId: 'user-1' },
      }),
    ];

    await Promise.all(promises);

    // All three delivered in send order
    expect(deliveryOrder).toEqual([
      'Notification 1',
      'Notification 2',
      'Notification 3',
    ]);

    // History should also reflect the order
    const logs = historyService.query({ recipient: 'https://hooks.example.com/test' });
    expect(logs).toHaveLength(3);
    expect(logs.map((l) => l.subject)).toEqual([
      'Notification 1',
      'Notification 2',
      'Notification 3',
    ]);
